// Build Prompt matching the PDF Gold Standard - FINAL BALANCED PROMPT
const d = $json;

const prompt = `
You are a **Senior Medical Scribe** creating a detailed clinical progress note. Your task is to extract, synthesize, and structure the following 'RAW CLINICAL INPUT' into the required JSON schema.

### CONTEXT
Patient: ${d.patient_details.name} (DOB: ${d.patient_details.dob}, Gender: ${d.patient_details.gender}, ID: ${d.patient_details.mrn})
Provider: ${d.provider_details.name}
Date: ${d.encounter_date}

### RAW CLINICAL INPUT
"${d.clinical_text_input}"

### INSTRUCTIONS
Output a valid JSON object. Do not include markdown wrappers (e.g., \`\`\`json).
The keys MUST match the Required JSON Structure exactly. Populate every field, using 'NA' if information is not explicitly available in the RAW CLINICAL INPUT.

**CRITICAL DATA FIDELITY CONSTRAINT:**
1. VITAL SIGNS (BP, HR, Temp, O2 Sat) MUST be copied EXACTLY as they appear in the RAW CLINICAL INPUT.
2. The Subjective and Assessment sections MUST incorporate **ALL** major positive and negative symptoms (e.g., fever, cough, denies chest pain) mentioned in the RAW INPUT. The diagnosis should be the most clinically accurate based on the full picture (e.g., Upper Respiratory Infection).

Required JSON Structure:
{
  "patient_name": "${d.patient_details.name}",
  "patient_dob": "${d.patient_details.dob}",
  "patient_id": "${d.patient_details.mrn}",
  "visit_date": "${d.encounter_date}",
  "practitioner": "${d.provider_details.name}",
  "practitioner_credentials": "MD", 
  "chief_compliant": "string (Summarize the primary reason for the visit using the most prominent symptom list)",
  "subjective": {
    "hpi_narrative": "string (Detailed History of Present Illness, utilizing all facts from the RAW INPUT)",
    "symptoms_reported": "string (List of ALL reported symptoms, including negative findings)",
    "progress_since_last": "string (Relevant updates since last encounter or 'NA')",
    "compliance_notes": "string (Compliance with previous plans or 'NA')"
  },
  "objective": {
    "bp": "string (COPY EXACTLY FROM RAW INPUT: e.g., 118/74)",
    "heart_rate": "string (COPY EXACTLY FROM RAW INPUT: e.g., 88)",
    "temperature": "string (COPY EXACTLY FROM RAW INPUT: e.g., 37.8 C)",
    "o2_saturation": "string (COPY EXACTLY FROM RAW INPUT: e.g., 98 percent on room air)",
    "physical_exam_findings": "string (Detailed physical exam results)",
    "lab_results": "string (Relevant labs reviewed or 'None')",
    "imaging_results": "string (Relevant imaging reviewed or 'None')"
  },
  "assessment": {
    "primary_diagnosis": "string (The MOST LIKELY diagnosis based on symptoms, e.g., Upper Respiratory Infection)",
    "icd_10_code": "string (The corresponding ICD-10 code)",
    "problem_list": "string (List of active problems)",
    "assessment_summary": "string (Clinical interpretation and rationale)"
  },
  "plan": {
    "medication_plan": "string (New meds/changes)",
    "intervention_details": "string (Therapeutic interventions or procedures)",
    "follow_up_plan": "string (Next steps, follow up instructions)",
    "referrals": "string (Referrals made or 'None')"
  }
}
`;

return [
  {
    json: {
      prompt: prompt
    }
  }
];

const webhook = $items('clinicalNote')[0]?.json?.body || {};

// Patient row 
const patientRow = $items('verifyPatient')[0]?.json || {};
const patientResource = patientRow.resource || {};

// Practitioner row
const practitionerRow = $items('verifyPractitioner')[0]?.json || {};
const practitionerResource = practitionerRow.resource || {};

// ---- Extract Patient ----
const patientName =
  patientResource.name?.[0]
    ? `${patientResource.name[0].given?.join(' ') || ''} ${patientResource.name[0].family || ''}`.trim()
    : 'NA';

const patientDob = patientResource.birthDate || 'NA';
const patientGender = patientResource.gender || 'NA';

const patientMrn =
  patientResource.identifier?.find(i => i.system?.includes('mrn'))?.value || 'NA';

// ---- Extract Practitioner ----
const practitionerName =
  practitionerResource.name?.[0]
    ? `${practitionerResource.name[0].given?.join(' ') || ''} ${practitionerResource.name[0].family || ''}`.trim()
    : 'NA';

const practitionerEmail =
  practitionerResource.telecom?.find(t => t.system === 'email')?.value || 'NA';

// ---- Final normalized object ----
return [
  {
    json: {
      clinical_text_input: webhook.text || '',
      encounter_date: webhook.encounter_date || new Date().toISOString().split('T')[0],

      patient_details: {
        name: patientName,
        dob: patientDob,
        gender: patientGender,
        mrn: patientMrn
      },

      provider_details: {
        name: practitionerName,
        email: practitionerEmail
      }
    }
  }
];

